text:
{
  "formal_minutes": {
    "decisions": {
      "confirmed": [
        {
          "item": "공개 릴리스 목표는 흡연(스모크) 테스트 통과 시 금요일 15:00 KST로 확정됨",
          "source": "회의록 본문"
        },
        {
          "item": "packageName 불일치 발생 시 스크립트를 무시하지 않고, 먼저 패키지 설정/구성 확인 후 계약 자체가 잘못된 경우에만 스크립트 재검토",
          "source": "회의록 본문"
        }
      ],
      "rejected_proposals": [
        {
          "item": "Hara의 제안(패키지명 불일치 시 smoke-theme-pack.mjs 무시)은 최종 반려됨",
          "source": "회의록 본문"
        }
      ],
      "internal_stretch_goals": [
        {
          "item": "수요일 공개 릴리스 제안은 내부 스트레치 골로 유지되며, 필수 목표가 아님",
          "source": "회의록 본문"
        }
      ],
      "non_decisions": [
        {
          "item": "README 설치 단계 리뷰는 목요일 예정으로 언급되었으나, 담당자/완료 여부는 미확정",
          "source": "회의록 본문"
        },
        {
          "item": "릴리스 최종 승인 권한자는 미정으로 남음",
          "source": "회의록 본문"
        },
        {
          "item": "내부 수요일 스트레치 골을 릴리스 노트에 반영할지 미결정",
          "source": "회의록 본문"
        }
      ]
    },
    "risks": [
      {
        "item": "tarball 경로가 잘못되면 릴리스가 지연될 수 있음",
        "source": "회의록 본문"
      },
      {
        "item": "README 설치 단계가 오래되면 사용자에게 오도된 릴리스 노트/가이드가 제공될 수 있음",
        "source": "회의록 본문"
      }
    ],
    "open_questions": [
      {
        "item": "최종 릴리스 승인 권한자는 누구인가?",
        "source": "회의록 본문"
      },
      {
        "item": "릴리스 노트에 내부 수요일 스트레치 골을 언급할지 여부는?",
        "source": "회의록 본문"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "금요일 10:00 KST까지 스모크 테스트를 재실행하고 결과 공유",
      "due": "2026-05-15 10:00 KST",
      "status": "요청됨",
      "source_certainty": "high"
    },
    {
      "owner": "Doyun",
      "task": "금요일 12:00 KST까지 action_items.md에 실패 트라이애지 노트 작성",
      "due": "2026-05-15 12:00 KST",
      "status": "요청됨",
      "source_certainty": "high"
    },
    {
      "owner": "미지정",
      "task": "README 설치 단계 검토 수행(목요일 가능 시)",
      "due": "미지정",
      "status": "미지정",
      "source_certainty": "high"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 스모크 결과를 공유한 후 생성된 tarball 경로 확인",
      "due": "미지정",
      "status": "요청됨",
      "source_certainty": "high"
    }
  ],
  "followup_note": {
    "next_checks": [
      "금요일 10:00 KST 스모크 테스트 결과 유무 및 통과/실패 판정 확인",
      "Doyun의 실패 트라이애지 노트(action_items.md) 제출 여부 확인",
      "tarball 경로 검증: Hara 확인 항목 완료 여부 점검",
      "릴리스 승인 권한자 확정 절차 진행",
      "릴리스 노트에 수요일 스트레치 골 기재 여부 최종 판단"
    ],
    "do_not_invent": [
      "고객/외부 파트너명",
      "예산/보안/장애/법무 승인",
      "추가 책임자(미지정 항목의 임의 지정)",
      "미정된 마감기한(명시되지 않은 데드라인)"
    ]
  },
  "non_invention_rules": [
    "제공된 회의 입력에 없는 사실을 추가하지 않는다.",
    "고객, 예산, 보안 사건, 운영 장애, 법무 승인, 담당자 미지정 항목의 소유자, 미지정 마감일을 생성하지 않는다.",
    "릴리스 일정은 확정사항(금요일 15:00 KST)과 스트레치 골(수요일)로 분리해 표현한다.",
    "모든 문구는 회의 원문 기반으로만 작성하며 해석 범위를 넘는 단정은 피한다."
  ]
}
